const body = $input.first().json.body || $input.first().json;
const faultBits = parseInt(body.value ?? body.fault_bits ?? 0);

if (faultBits === 0) return [];

const bitMap = {
  0: { name: 'infeed_conveyor', label: 'Infeed Conveyor', priority: 'HIGH' },
  1: { name: 'labeler', label: 'Labelaar', priority: 'MEDIUM' },
  2: { name: 'sealer', label: 'Sealer', priority: 'HIGH' },
  3: { name: 'vision_system', label: 'Vision Systeem', priority: 'LOW' }
};

const activeFaults = [];
for (let bit = 0; bit <= 3; bit++) {
  if (faultBits & (1 << bit)) {
    activeFaults.push(bitMap[bit]);
  }
}

return [{
  json: {
    fault_bits_raw: faultBits,
    active_faults: activeFaults,
    fault_count: activeFaults.length,
    has_high_priority: activeFaults.some(f => f.priority === 'HIGH'),
    detected_at: new Date().toISOString(),
    plc: 'PLC_02',
    work_center: 'WC-CONV-01'
  }
}];

